trigger.script:
local newControllerId = CreateNewObject { prototypeName = "someNPCMotionController", objName = "FURYVEHICLE3" }
local newController = GetEntityByID(newControllerId) local FVehicle = GetEntityByName("FuryCar3_vehicle_0") if FVehicle then newController:setVehicleUnderControl(FVehicle) end
trigger:Deactivate()
